class Solution {
public:
    int lengthAfterTransformations(string s, int t, vector<int>& nums) {
        const long long MOD = 1'000'000'007;
        vector<long long> cnt(26, 0);
        for (char c : s) cnt[c - 'a']++;

        vector<vector<long long>> mat(26, vector<long long>(26, 0));
        for (int i = 0; i < 26; ++i) {
            int len = nums[i];
            for (int j = 0; j < len; ++j) {
                int next = (i + 1 + j) % 26;
                mat[i][next] += 1;
            }
        }

        auto multiply = [&](const vector<vector<long long>>& a, const vector<vector<long long>>& b) -> vector<vector<long long>> {
            vector<vector<long long>> res(26, vector<long long>(26, 0));
            for (int i = 0; i < 26; ++i)
                for (int k = 0; k < 26; ++k)
                    if (a[i][k])
                        for (int j = 0; j < 26; ++j)
                            res[i][j] = (res[i][j] + a[i][k] * b[k][j]) % MOD;
            return res;
        };

        auto matrix_pow = [&](vector<vector<long long>> base, int power) -> vector<vector<long long>> {
            vector<vector<long long>> res(26, vector<long long>(26, 0));
            for (int i = 0; i < 26; ++i) res[i][i] = 1;
            while (power) {
                if (power & 1) res = multiply(res, base);
                base = multiply(base, base);
                power >>= 1;
            }
            return res;
        };

        vector<vector<long long>> trans = matrix_pow(mat, t);
        vector<long long> res(26, 0);
        for (int i = 0; i < 26; ++i)
            for (int j = 0; j < 26; ++j)
                res[j] = (res[j] + cnt[i] * trans[i][j]) % MOD;

        long long ans = 0;
        for (long long x : res) ans = (ans + x) % MOD;
        return (int)ans;
    }
};
